// Formater la liste des instances
const response = $input.item.json.result || $input.item.json;
const instances = response.data || response.instances || [];

if (instances.length === 0) {
  return {
    json: {
      success: true,
      message: "Aucune instance BunkerWeb enregistrée.",
      instances: []
    }
  };
}

let formattedText = `Instances BunkerWeb enregistrées (${instances.length}) :\n\n`;

instances.forEach((instance, idx) => {
  const status = instance.status === 'up' || instance.status === 'running' ? '✅ Active' : '❌ Inactive';
  formattedText += `${idx + 1}. **${instance.hostname}** - ${status}\n`;
  formattedText += `   • Type: ${instance.type || 'N/A'}\n`;

  if (instance.method) {
    formattedText += `   • Méthode: ${instance.method}\n`;
  }
  if (instance.server_name) {
    formattedText += `   • Server Name: ${instance.server_name}\n`;
  }
  if (instance.last_seen) {
    const lastSeen = new Date(instance.last_seen).toLocaleString('fr-FR');
    formattedText += `   • Dernière activité: ${lastSeen}\n`;
  }
  formattedText += '\n';
});

return {
  json: {
    success: true,
    message: formattedText,
    instances: instances,
    count: instances.length
  }
};
